-- World Business Plus — full catalog import (with images). Safe to re-run.

alter table products add column if not exists price numeric;
alter table products add column if not exists images jsonb not null default '[]'::jsonb;

on conflict (id) do nothing;

delete from products;

on conflict (id) do update set code=excluded.code,name=excluded.name,cat=excluded.cat,brand=excluded.brand,price=excluded.price,active=excluded.active,image_url=excluded.image_url,images=excluded.images,sort=excluded.sort;

